var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"일단은 제가 네퀴티아에게 남아 있는 인간성이라고 가정해 볼게요.","JPN":"とりあえず私がネキティアに残っている人間性だと仮定しましょう。","ENG":"Let's say I'm the last humanity remaining within Nequitia, for now.","TWN":"總之，先假設我是莉奎蒂亞殘存的人性。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"여지 없는 사실이다. 나는 너에게 거짓을 이르지 않았으니.","JPN":"疑いようのない事実だ。我はそなたに嘘などついておらぬ。","ENG":"It is the irrefutable truth. I have not told you a lie.","TWN":"這是不爭的事實，我沒有對你說謊。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"말이 그렇다는 거예요.","JPN":"それはわかっています。","ENG":"I'm just saying.","TWN":"我說說而已。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"만약 그렇다면, 어째서 한가롭게 열차 여행이나 하고 있는 거죠?","JPN":"だとしたら、どうして私は呑気に列車の旅なんてやっているんですか？","ENG":"If so, why am I on a leisurely train ride?","TWN":"假設真是如此，那我為何還悠哉地火車旅行呢？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네퀴티아….","JPN":"ネキティア……","ENG":"Nequitia...","TWN":"莉奎蒂亞…"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"다시 말해, 너에게 이 열차의 모든 것은 어디론가 멀리 떠나보내야 할 경험들이다.","JPN":"つまり、そなたにとってこの列車で起こるすべては、どこか遠くに追いやるべき経験なのだ。","ENG":"In other words, for you, this train embodies the experiences you are to send somewhere distant.","TWN":"我再說一次，這台列車裡的一切對你而言，就是要送到遠方某處的經歷。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"우리 그냥 구분해서 말하면 어때요?","JPN":"そうやって毎回二度言うのはやめませんか？","ENG":"How about we just separate the two?","TWN":"可以不要一直把我們混為一談嗎？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"고지식하게 매번 지적해 주지 않아도 잘 알고 있거든요. 네퀴티아가 저라는 건.","JPN":"いちいち言われなくてもわかっています、私がネキティアなのは。","ENG":"I'm well aware that I'm Nequitia. You don't have to point it out every time.","TWN":"不需要你一直提醒我，我也知道我就是莉奎蒂亞。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"좋다. 그러길 원한다면.","JPN":"よかろう。そう望むなら。","ENG":"Very well. If that is your wish.","TWN":"好吧，就照你的意思。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"하지만 네퀴티아 자신도 어디로 보내야 할지, 어떻게 보내야 할지는 모르고 있는 모양이더군.","JPN":"だが、ネキティア自身もどこに追いやるべきか、どう追いやるべきかをわかっていないようだ。","ENG":"However, it seemed like Nequitia herself did not know where to send the train, or how to send one.","TWN":"不過莉奎蒂亞自己似乎也不知道要送去哪，又該如何送。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래서 같은 철로를 계속 달리는 열차란 말이죠.","JPN":"だから列車が同じ線路を走り続けている、ということですね。","ENG":"And that's why this train runs endlessly on the same track.","TWN":"所以才會一直重複相同的路線對吧。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하고 다니는 짓이랑 안 맞게 마음만은 소녀네요. 나 원, 참.","JPN":"やっていることとは裏腹に、心は少女のようですね。呆れるわ、まったく。","ENG":"She's a little girl on the inside while doing the opposite on the outside. How ironic.","TWN":"和她平時的作風一點都不像，內心根本還是少女吧，真是的。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"왜 갑자기 멈춰요?","JPN":"急に止まって、どうしたんですか？","ENG":"Why did you stop?","TWN":"怎麼突然不說話？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이 문을 열고 들어가면 다음 객차다, 레아 슈나이더.","JPN":"このドアを開ければ次の客車だ、レア・シュナイダー。","ENG":"Beyond this gate is the next passenger vehicle, Leah Schneider.","TWN":"打開這道門後就是下一節車廂，蕾亞·修奈德。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"객차마다 무엇이 있는지는 나 역시 명확히 알지 못한다.","JPN":"客車ごとに何があるかは、我とて正確にはわからぬ。","ENG":"I do not know of what lies in each passenger vehicle.","TWN":"我也無法明確掌握每節車廂裡會出現什麼。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그러니 무엇을 보더라도 삼켜지지 마라.","JPN":"ゆえに、何を目にしたとしても飲まれるな。","ENG":"Therefore, do not get consumed by whatever it is that you witness.","TWN":"所以不管你等下看到什麼，都不要被吞吃掉。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"방금 전에 죽다 살아난 사람에게 너무 과한 요구네요.","JPN":"ついさっきまで死にかけていた人にとっては無茶な要求ですね。","ENG":"Seems like a tall order for someone who just almost died.","TWN":"這個要求對於一個才剛從死裡逃生的人來說似乎有點勉強。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그럼 삼켜지면 어떻게 되는지는 알고 있나요?","JPN":"それで、飲まれたらどうなるんですか？","ENG":"Then, what happens when I'm consumed?","TWN":"你知道要是被吞吃掉會怎麼樣嗎？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"모른다.","JPN":"知らぬ。","ENG":"I do not know.","TWN":"不知道。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"하지만 수많은 경험 중 하나에 매몰되어 버릴 정도라면.","JPN":"だが、数々の経験のうちの一つに飲まれる程度なら。","ENG":"However, if you were to become submerged in one of those countless experiences.","TWN":"應該就會被困在眾多經驗中的其中一個吧。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"열차를 멈추는 건 포기하는 편이 낫겠지.","JPN":"列車を止めるのは諦めた方がいいだろう。","ENG":"You had better abandon hope of stopping the train.","TWN":"勸你還是放棄讓列車停駛吧。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇단 말이죠….","JPN":"なるほど……","ENG":"All right...","TWN":"既然如此…"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"재미있네요. 어디까지 나아갈 수 있나 한 번 해 보죠.","JPN":"面白いですね。どこまで行けるかやってみましょう。","ENG":"Interesting. Let's see how far I can go, then.","TWN":"有意思，那就看看我能堅持到哪裡吧。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"맞아. 나도 최선을 다해야지.","JPN":"そうだ。私も全力で頑張らなくちゃ。","ENG":"Right. I need to try my best, too.","TWN":"沒錯，我也必須要盡我所能。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"██도 나름대로 노력하고 있을 텐데, 부끄러운 모습을 보일 수는 없으니까.","JPN":"██もきっと努力している。恥ずかしいところなんか見せられない。","ENG":"██ is probably trying hard. I shouldn't embarrass myself.","TWN":"██也在努力，我不能丟人。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"……아.","JPN":"……あれ。","ENG":"...Oh.","TWN":"……不過，"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"██가…… 누구였더라.","JPN":"██って……誰だっけ。","ENG":"Who was... ██?","TWN":"██……是誰呢？"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님!","JPN":"マエストロ！","ENG":"Chief Conductor!","TWN":"指揮家！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"읏……?!","JPN":"うっ……！？","ENG":"Kgh...?!","TWN":"呃……？！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"신도들이 안전한 곳을 찾아 이 곳으로 모여들고 있어요.","JPN":"信徒たちが安全な場所を求めてここに集まってきています。","ENG":"The followers are gathering here for shelter.","TWN":"信徒們正聚集到這裡來要尋求安全的地方。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이대로는 문이 오래 버티지 못해요. 처리해야 합니다.","JPN":"このままでは扉が長く持ちません。殺すべきです。","ENG":"The door won't last long. We need to take care of them.","TWN":"這樣下去門擋不了多久的，必須做出應對措施。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"신도들이라니? 어떤 신도 말이야?","JPN":"信徒って？　なんのこと？","ENG":"Followers? What followers?","TWN":"信徒？什麼信徒？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"갑자기 왜 그러세요? 그야 당연히 교단의 신도들이죠.","JPN":"いきなり何をおっしゃっているのですか？　もちろん教団の信徒のことです。","ENG":"Why are you disoriented all of a sudden? The followers of the Order, of course.","TWN":"你怎麼了？當然是教團的信徒。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"아아, 위대한 정적이시여!","JPN":"おお、偉大な静寂よ！","ENG":"Aah! Oh, Great Silence!","TWN":"偉大的寂靜！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"교단의 성직자들이 어째서 우리를 들여보내 주지 않는단 말입니까!","JPN":"教団の聖職者であるあなたが、どうして我々を中に入れることを拒むのですか！","ENG":"Why won't the Order's clergy open the doors for us?!","TWN":"教團的聖職人員為何不放我們進去！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_METAL_KNOCK"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"여기 교단의 병사들도 있습니다! 저희만으로는 이 많은 사람들을 지킬 수 없어요!","JPN":"ここには教団の兵士たちもいます！　我々だけではこの数の信徒を守りきることはできません！","ENG":"There are soldiers of the Order as well! We cannot protect everyone by ourselves!","TWN":"這裡也有教團的士兵！光憑我們是無法保護這麼多人的！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"제발 문을 열어 주세요! 아니, 우리 아이만이라도 들여보내 주세요!","JPN":"扉を開けてください！　いいえ、せめて子どもたちだけでも！","ENG":"Please, open the door for us! Or at least let our children in!","TWN":"請開門！拜託，至少放我們的孩子進去就好！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_METAL_KNOCK"},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"정신 차리세요, 지휘자님.","JPN":"しっかりしてください、マエストロ。","ENG":"Compose yourself, Chief Conductor.","TWN":"指揮家，振作一點。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"타기리온의 하수인들이 지금 이 도시를 제 집처럼 휘젓고 다니고 있어요.","JPN":"タギリオンの手下どもが都市全体を襲撃しています。","ENG":"Thagirion's minions are swarming the city like it's their own neighborhood.","TWN":"塔基里翁的手下正在破壞這座城市。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이 곳 성전은 공세 직전에 축가를 완성해서 당분간 안전하지만….","JPN":"この聖殿は攻撃が始まる前に祝歌を完成させたのでしばらくは安全ですが……","ENG":"It'll be safe here for a while since we've completed the hymn for this temple before the attack...","TWN":"聖殿這裡在出事前就已經完成聖歌，所以暫時是安全的…"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"저 문이 열리면 그것도 끝이에요.","JPN":"あの扉が開けば、それすらも終わりです。","ENG":"But that won't last if that door is open.","TWN":"但只要一開門，就會暴露在危險之中。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그럼 밖에 있는 시민들이 전부 죽을 때까지 내버려 두자고?","JPN":"じゃあ外にいる市民は全員死ぬまで放っておくってこと？","ENG":"Then, you'd rather wait until all the citizens outside die?","TWN":"所以我們要看著外面那些人等死？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"같은 종교를 믿는 사람들인데도…. 저항할 힘이 없는 사람들인데도?","JPN":"同じ宗教を信じる者たちなのに……抗う力を持たない者たちなのよ？","ENG":"Even if they're of the same faith...? Even if they have no power to fight back?","TWN":"就算他們是我們的弟兄姊妹…就算他們是手無寸鐵的人？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님, 무슨 말씀이세요?","JPN":"マエストロ、何をおっしゃっているのですか？","ENG":"What do you mean, Chief Conductor?","TWN":"指揮家，你在說什麼？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"위대한 정적을 부르짖는 소리가 들리지 않으시나요?","JPN":"偉大な静寂を叫ぶ音が聞こえないのですか？","ENG":"Can't you hear their desperate cries for the Great Silence?","TWN":"你沒聽到他們嘴裡喊的是偉大的寂靜嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"안타깝지만 저들의 비명과 절규는 원정을 떠나신 에클레시아 예하의 권능이 되어 주겠죠.","JPN":"残念ながら、あの者たちの悲鳴と絶叫は遠征に出かけられたエクレシア猊下の力の養分となるでしょう。","ENG":"It's a shame, but at least their screams and cries will add to the power of Her Eminence Ecclesia, who is currently on an expedition.","TWN":"我很遺憾，他們的哀號和慘叫聲，會成為出征艾可露西亞主教的權能。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"에클레시아……?","JPN":"エクレシア……？","ENG":"Ecclesia...?","TWN":"艾可露西亞……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"예하의 성흔은 <color=#ffd34c>믿음이 곧 힘일지니</color>.","JPN":"猊下の聖痕は<color=#ffd34c>信仰こそ力なり</color>。","ENG":"The Stigmata of her Eminence, <color=#ffd34c>Fortitude in Faith</color>.","TWN":"主教的聖痕是<color=#ffd34c>信心即是力量</color>。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"뭇 병정들의 신뢰는 물론, 위대한 정적의 대리인으로서 신앙을 한 몸에 받고 계시지만…","JPN":"多くの兵隊からの信頼はもちろん、偉大な静寂の代理人として信仰をその身に集められていますが……","ENG":"Her Eminence carries all the faith of countless soldiers as the representative of the Great Silence, but...","TWN":"身為偉大的寂靜的代理人，信徒的信念都聚集在她身上…"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"타기리온을 쓰러뜨리려면 아무리 보태도 충분하지 않죠.","JPN":"タギリオンを倒すためには、いくらあっても足りないぐらいです。","ENG":"It will never be enough to take on Thagirion.","TWN":"但還是不足以擊倒塔基里翁。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"애초에 저희를 공세가 시작될 이 도시로 이끌고 오신 건, 최고 지휘자님의 뜻 아니었나요?","JPN":"そもそも襲撃されるはずのこの都市に私たちを連れてきたのは、マエストロの御意向だったではありませんか？","ENG":"And was it not your will to bring us to this city, where the attacks were going to begin?","TWN":"我們之所以會來到這座成為攻擊目標的城市，不是指揮家你的意思嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"예하의 성흔이 작용하는 기재를 연구하기 위해서요.","JPN":"猊下の聖痕が作用する機制を研究するためにです。","ENG":"To study the mechanism in which the Stigmata of Her Eminence works.","TWN":"因為要研究主教聖痕作用的機制。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"저들은 모두 교단의 미래를 위한 반석이 되어 줄 거예요.","JPN":"あの者たちは皆、教団の未来のための布石となってくれるでしょう。","ENG":"They will all become a stepping stone for the Order's future.","TWN":"他們都會成為教團未來的根基。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"……지휘자님?","JPN":"……マエストロ？","ENG":"...Chief Conductor?","TWN":"……指揮家？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"닥치고 어서 저 문 열어.","JPN":"黙って早くあの扉を開けなさい。","ENG":"Shut up and open that door.","TWN":"閉上你的嘴，給我開門。"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이 신전에는 저희가 가져 온 귀중한 기재와 연구 자료들도 잔뜩 있어요.","JPN":"この神殿には私たちが持ってきた大事な機材や研究資料がたくさんあります。","ENG":"This temple holds valuable equipment and research materials that we brought here.","TWN":"聖殿裡存放許多我們帶來的珍貴紀錄和研究資料，"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그 중 하나라도 바깥에 유출되기라도 하면, 성도들조차 저희에게 등 돌릴지도 모를 텐데요?","JPN":"そのうちの一つでも外に知られれば、信徒ですら私たちから離れていくかもしれないんですよ？","ENG":"If even one of them is leaked, the followers might turn their back on us.","TWN":"萬一洩漏出去，信徒很可能會離我們而去。"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"주둥이 닥치고 어서 열라고!","JPN":"その口を閉じて、早く扉を開けなさい！","ENG":"Just shut your mouth and open the door!","TWN":"我叫你閉嘴，馬上開門！"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"……희한하네.","JPN":"……おかしいわね。","ENG":"...Odd.","TWN":"……真是稀奇。"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우리 지휘자님께서 박애주의자라는 건 알고 있었지만 말이야.","JPN":"マエストロが博愛主義者なのはわかっていたけれど。","ENG":"I knew our dear Conductor was a philanthropist.","TWN":"我知道指揮家很博愛，"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"한 입으로 두 말 할 만큼 가증스러우시진 않았던 걸로 기억하는데?","JPN":"コロコロ言うことを変えるほどおぞましい方だったかしら？","ENG":"But I don't remember her being so despicable that she'd take back her own words.","TWN":"但應該不是出爾反爾的可恨之人吧？"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아윽! 다리가……?!","JPN":"くっ！　脚が……！？","ENG":"Errgh! My leg...?!","TWN":"唔呃！我的腿……？！"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"자, 이리 와. 내가 그 눈에 똑똑히 새겨 줄 테니까.","JPN":"こっちにいらっしゃい。私がその目にちゃんと焼きつけてあげる。","ENG":"Now, come here. I'll show you something you'll never forget.","TWN":"給我過來，我要烙印在你的眼裡。"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"큭……! 이거 놓지 못해!","JPN":"くっ……！　離せ！","ENG":"Kgh...! Let me go!","TWN":"呃……！放開我！"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아윽……! 아아아악!!","JPN":"あうっ……！　ああああっ！！","ENG":"Agh...! AHHHH!!","TWN":"呃呃……！啊啊啊啊！！"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"절름발이나 앉은뱅이나 마찬가지지? 그래도 정이 있어서 깔끔하게 잘라 줬어.","JPN":"歩けない脚はいらないでしょ？　でもかわいそうだから綺麗に切ってあげたわ。","ENG":"Having a limp, or being unable to walk is the same thing. But still, I made a clean cut since I don't completely hate you.","TWN":"瘸腿或癱子都是一樣的吧？不過念在過往的情分上，我有砍得乾淨俐落。"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"자, 저기 창문까지 끌고 가 줄게. 지휘자님을 위한 특등석이야.","JPN":"さあ、窓のところまで連れていってあげるわね。マエストロのための特等席よ。","ENG":"Now, let me drag you to the windows over there. You won't miss a thing from that first-class seat over there.","TWN":"來，我帶你到窗戶那裡，那是我為你準備的貴賓席。"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"헉……! 허억……!","JPN":"はっ……！　はぁっ……！","ENG":"Kgh...! Khhh...!","TWN":"咳……！咳……！"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"당신이 선택한 결과야.","JPN":"あなたが選んだ結果よ。","ENG":"This is what you chose.","TWN":"這是你選擇的結果。"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이 기회에 다시 곱씹어 볼까요?","JPN":"これを機にもう一度自分の目で確認して？","ENG":"Shall we go over it once more?","TWN":"你就趁這個機會再回味一下吧？"},"stage":{"bg":"CHURCH","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};